        <button class="btn btn-secondary" onclick="showPunchline()">Reveal Punchline 👀</button>
    </div>

    <script>
        const jokes = [
            {
                setup: "Why don't scientists trust atoms?",
                punchline: "Because they make up everything! 😄"
            },
            {
                setup: "Why did the scarecrow win an award?",
                punchline: "Because he was outstanding in his field! 🌾"
            },
            {
                setup: "Why don't eggs tell jokes?",
                punchline: "Because they'd crack each other up! 🥚"
            },
            {
                setup: "What do you call a fake noodle?",
                punchline: "An impasta! 🍝"
            }
        ];

        let punchlineVisible = false;

        function getJoke() {
            const randomIndex = Math.floor(Math.random() * jokes.length);
            const joke = jokes[randomIndex];

            document.getElementById('placeholder').style.display = 'none';
            document.getElementById('jokeSetup').textContent = joke.setup;
            document.getElementById('jokePunchline').textContent = joke.punchline;
            document.getElementById('jokePunchline').style.display = 'none';

            punchlineVisible = false;
        }

        function showPunchline() {
            const punchline = document.getElementById('jokePunchline');
            const setup = document.getElementById('jokeSetup').textContent;

            if (!setup) {
                alert("Get a joke first!");
                return;
            }

            if (!punchlineVisible) {
                punchline.style.display = 'block';
                punchlineVisible = true;
            }
        }
    </script>

</body>
